+@import "tailwindcss";
+
+/* ==========================================================================
+   FrankenSQLite - Global Styles
+   Stripe-Grade Monster Technical Design System
+   ========================================================================== */
+
+:root {
+  /* -- Font Stacks -------------------------------------------------------- */
+  --font-sans: "Inter", var(--font-inter), ui-sans-serif, system-ui, sans-serif;
+  --font-mono: "JetBrains Mono", var(--font-jetbrains), ui-monospace, monospace;
+
+  /* -- Refined Typography (Stripe-Grade) -------------------------------- */
+  --tracking-tightest: -0.04em;
+  --tracking-tighter: -0.02em;
+  --tracking-tight: -0.01em;
+  --tracking-normal: 0em;
+  --tracking-wide: 0.025em;
+  --tracking-widest: 0.1em;
+
+  /* -- Refined Palette (Franken-High-End) -------------------------------- */
+  --color-bg: #020a05;
+  --color-surface: #051210;
+  --color-border: rgba(20, 184, 166, 0.1);
+  --color-green-prime: #14b8a6;
+  --color-green-glow: #2dd4bf;
+  --color-lime-prime: #5eead4;
+
+  /* -- Elevation & Depth -------------------------------------------------- */
+  --shadow-sm: 0 1px 2px rgba(0, 0, 0, 0.5);
+  --shadow-md: 0 4px 6px -1px rgba(0, 0, 0, 0.3), 0 2px 4px -1px rgba(0, 0, 0, 0.2);
+  --shadow-lg: 0 10px 15px -3px rgba(0, 0, 0, 0.4), 0 4px 6px -2px rgba(0, 0, 0, 0.2);
+  --shadow-franken: 0 0 40px -10px rgba(20, 184, 166, 0.2);
+
+  /* -- Animation Timings -------------------------------------------------- */
+  --ease-stripe: cubic-bezier(0.19, 1, 0.22, 1);
+  --duration-fast: 200ms;
+  --duration-normal: 400ms;
+  --duration-slow: 700ms;
+}
+
+/* --------------------------------------------------------------------------
+   2. Typography System
+   -------------------------------------------------------------------------- */
+
+body {
+  background-color: var(--color-bg);
+  color: #f1f5f9;
+  font-family: var(--font-sans);
+  font-feature-settings: "cv02", "cv03", "cv04", "cv11";
+  -webkit-font-smoothing: antialiased;
+  -moz-osx-font-smoothing: grayscale;
+  line-height: 1.6;
+  letter-spacing: var(--tracking-tight);
+  overflow-x: hidden;
+}
+
+h1, h2, h3, h4 {
+  letter-spacing: var(--tracking-tighter);
+  font-weight: 900;
+  line-height: 1.1;
+}
+
+code, pre {
+  font-family: var(--font-mono);
+  letter-spacing: var(--tracking-normal);
+}
+
+/* --------------------------------------------------------------------------
+   3. Global Effects
+   -------------------------------------------------------------------------- */
+
+/* Subtle noise overlay (inline; avoids external requests). */
+body::before {
+  content: "";
+  position: fixed;
+  inset: 0;
+  width: 100%;
+  height: 100%;
+  background-image: url("data:image/svg+xml,%3Csvg%20xmlns%3D%27http%3A//www.w3.org/2000/svg%27%20width%3D%27120%27%20height%3D%27120%27%3E%3Cfilter%20id%3D%27n%27%3E%3CfeTurbulence%20type%3D%27fractalNoise%27%20baseFrequency%3D%270.85%27%20numOctaves%3D%272%27%20stitchTiles%3D%27stitch%27%20seed%3D%272%27/%3E%3C/filter%3E%3Crect%20width%3D%27120%27%20height%3D%27120%27%20filter%3D%27url(%23n)%27/%3E%3C/svg%3E");
+  opacity: 0.03;
+  pointer-events: none;
+  z-index: 9999;
+  contain: strict;
+  will-change: auto;
+}
+
+/* Custom Selection */
+::selection {
+  background: rgba(20, 184, 166, 0.3);
+  color: #fff;
+}
+
+/* --------------------------------------------------------------------------
+   4. Scrollbar Styling
+   -------------------------------------------------------------------------- */
+
+::-webkit-scrollbar {
+  width: 10px;
+}
+
+::-webkit-scrollbar-track {
+  background: #010503;
+}
+
+::-webkit-scrollbar-thumb {
+  background: #1a2e2a;
+  border: 2px solid #010503;
+  border-radius: 10px;
+  transition: background 0.3s;
+}
+
+::-webkit-scrollbar-thumb:hover {
+  background: var(--color-green-prime);
+}
+
+/* --------------------------------------------------------------------------
+   5. Design Components
+   -------------------------------------------------------------------------- */
+
+/* Stripe-style adaptive glass */
+.glass-modern {
+  background: rgba(5, 18, 16, 0.8);
+  backdrop-filter: blur(12px) saturate(120%);
+  -webkit-backdrop-filter: blur(12px) saturate(120%);
+  border: 1px solid rgba(20, 184, 166, 0.12);
+  box-shadow:
+    0 4px 24px -1px rgba(0, 0, 0, 0.4),
+    inset 0 1px 1px rgba(255, 255, 255, 0.05);
+}
+
+/* Kinetic Hover Effect */
+.kinetic-card {
+  transition: all var(--duration-normal) var(--ease-stripe);
+}
+
+.kinetic-card:hover {
+  transform: translateY(-4px) scale(1.01);
+  border-color: rgba(20, 184, 166, 0.3);
+  box-shadow: var(--shadow-franken);
+}
+
+/* Living Gradient Text */
+.text-animate-green {
+  background: linear-gradient(
+    to right,
+    #2dd4bf,
+    #5eead4,
+    #14b8a6,
+    #2dd4bf
+  );
+  background-size: 300% auto;
+  -webkit-background-clip: text;
+  background-clip: text;
+  color: transparent;
+  animation: textGradient 8s linear infinite;
+}
+
+@keyframes textGradient {
+  to { background-position: 300% center; }
+}
+
+/* Smooth float animation */
+@keyframes float {
+  0% { transform: translateY(0px) rotate(0deg); }
+  50% { transform: translateY(-10px) rotate(1.5deg); }
+  100% { transform: translateY(0px) rotate(0deg); }
+}
+
+.animate-float {
+  animation: float 6s ease-in-out infinite;
+}
+
+/* Border beam sweep (CSS-only, compositor-friendly) */
+@keyframes borderBeam {
+  0% { top: -100%; left: -100%; }
+  100% { top: 100%; left: 100%; }
+}
+
+.animate-border-beam {
+  animation: borderBeam 4s linear infinite;
+}
+
+/* Reduced motion: disable continuous animations */
+@media (prefers-reduced-motion: reduce) {
+  .text-animate-green {
+    animation: none;
+    background-size: 100% auto;
+  }
+
+  .animate-float {
+    animation: none;
+  }
+
+  .animate-border-beam {
+    animation: none;
+  }
+
+  .kinetic-card:hover {
+    transform: none;
+  }
+}
+
+/* --------------------------------------------------------------------------
+   6. Utilities
+   -------------------------------------------------------------------------- */
+
+.text-gradient-franken {
+  background: linear-gradient(135deg, #2dd4bf 0%, #5eead4 50%, #14b8a6 100%);
+  -webkit-background-clip: text;
+  background-clip: text;
+  -webkit-text-fill-color: transparent;
+}
+
+.glow-green {
+  box-shadow: 0 0 40px rgba(20, 184, 166, 0.15);
+}
+
+/* Slow spin for flywheel idle state */
+@keyframes spinSlow {
+  from { transform: rotate(0deg); }
+  to { transform: rotate(360deg); }
+}
+
+.animate-spin-slow {
+  animation: spinSlow 12s linear infinite;
+}
+
+/* Custom scrollbar for flywheel detail panel */
+.custom-scrollbar::-webkit-scrollbar {
+  width: 4px;
+}
+
+.custom-scrollbar::-webkit-scrollbar-track {
+  background: transparent;
+}
+
+.custom-scrollbar::-webkit-scrollbar-thumb {
+  background: rgba(20, 184, 166, 0.2);
+  border-radius: 10px;
+}
+
+.custom-scrollbar::-webkit-scrollbar-thumb:hover {
+  background: rgba(20, 184, 166, 0.4);
+}
+
+@media (prefers-reduced-motion: reduce) {
+  .animate-spin-slow {
+    animation: none;
+  }
+}
+
+/* ── Accessibility Skip Link ───────────────────────────────────────── */
+.skip-link {
+  position: absolute;
+  top: -100px;
+  left: 50%;
+  transform: translateX(-50%);
+  background: var(--color-green-prime);
+  color: black;
+  padding: 1rem 2rem;
+  z-index: 9999;
+  font-weight: 900;
+  text-transform: uppercase;
+  letter-spacing: 0.2em;
+  border-radius: 0 0 1rem 1rem;
+  transition: top 0.3s var(--ease-stripe);
+}
+
+.skip-link:focus {
+  top: 0;
+  outline: none;
+}
+
+:focus-visible {
+  outline: 2px solid var(--color-green-prime);
+  outline-offset: 4px;
+}
+
+/* ── highlight.js: Franken-Teal Theme ────────────────────────── */
+
+pre code.hljs {
+  display: block;
+  overflow-x: auto;
+  padding: 1em;
+}
+
+.hljs {
+  color: #e2e8f0;
+  background: transparent;
+}
+
+.hljs-comment,
+.hljs-quote {
+  color: #475569;
+  font-style: italic;
+}
+
+.hljs-keyword,
+.hljs-selector-tag,
+.hljs-literal,
+.hljs-section,
+.hljs-link {
+  color: #2dd4bf;
+  font-weight: 800;
+}
+
+.hljs-function .hljs-keyword {
+  color: #14b8a6;
+}
+
+.hljs-string,
+.hljs-doctag {
+  color: #5eead4;
+}
+
+.hljs-type,
+.hljs-number,
+.hljs-class .hljs-title,
+.hljs-variable,
+.hljs-template-variable,
+.hljs-tag .hljs-attr {
+  color: #fbbf24;
+}
+
+.hljs-name,
+.hljs-symbol,
+.hljs-bullet,
+.hljs-addition {
+  color: #99f6e4;
+}
+
+.hljs-title,
+.hljs-section,
+.hljs-selector-id {
+  color: #2dd4bf;
+  font-weight: 900;
+}
+
+.hljs-subst {
+  color: #e2e8f0;
+}
+
+.hljs-identifier {
+  color: #f1f5f9;
+}
+
+.hljs-attr {
+  color: #14b8a6;
+}
+
+.hljs-attribute {
+  color: #94a3b8;
+}
+
+.hljs-deletion {
+  color: #f87171;
+}
+
+.hljs-emphasis {
+  font-style: italic;
+}
+
+.hljs-strong {
+  font-weight: bold;
+}
+

