+          style={{ x, y, left: p.offsetX, top: p.offsetY }}
+          animate={{ opacity: [0, 1, 0], y: [0, -20, -40], x: [0, p.drift1, p.drift2] }}
+          transition={{ duration: p.duration, repeat: Infinity, ease: "linear" }}>{p.char}</motion.div>
+      ))}
+    </div>
+  );
+}
