+
+        {/* Right: FrankenSQLite */}
+        <Panel
+          label="FrankenSQLite"
+          sublabel="MVCC Parallel Writers"
+          tps={rightTps}
+          accent={true}
+          svgH={svgH}
+        >
+          <MultiWriterViz writers={state.right} count={writerCount} svgH={svgH} />
+        </Panel>
+      </div>
+
+      {/* Controls */}
+      <div className="flex flex-wrap items-center gap-4">
