+      if (!lockTaken && w.x >= LOCK_X - 16) {
+        w.state = "writing";
+        w.progress = 0;
+        lockTaken = true;
+      }
+    } else if (w.state === "writing") {
+      w.progress += dt * 1.0;
+      if (w.progress >= 1) {
+        w.state = "done";
+        w.progress = 0;
+        completedLeft++;
+      }
+    } else if (w.state === "done") {
+      w.progress += dt * 1.5;
+      if (w.progress >= 1) {
+        w.state = "queued";
+        w.x = 20 + Math.random() * 30;
+        w.progress = 0;
+        w.targetPage = Math.floor(Math.random() * PAGE_COUNT);
