+  const logPLoss = logComb + (R + 1) * Math.log10(p);
+  const pLoss = logPLoss < -300 ? 0 : Math.pow(10, logPLoss);
+  const nines = logPLoss < -300 ? 300 : -logPLoss;
+
+  return { pLoss, nines, R };
