+    for (const committed of committedTxns) {
+      const overlap = txnToCommit.readSet.filter(page => committed.writeSet.includes(page));
+      if (overlap.length > 0) {
+        conflictFound = true;
+        conflictDetails = `${committed.id} already modified Page ${overlap[0]}`;
+        break;
+      }
