+        <motion.rect
+          key={`${side}-${cell.idx}`}
+          x={cell.cx}
+          y={cell.cy}
+          width={CELL_SIZE}
+          height={CELL_SIZE}
+          rx={4}
+          animate={{
+            fill: getCellColor(cell.idx, step, side),
+          }}
+          transition={{ duration: dur, delay: cell.idx * 0.005 }}
+          stroke="rgba(255,255,255,0.06)"
+          strokeWidth={0.5}
+        />
+      ))}
+    </g>
+  );
+}
